const webhook_data = $('Webhook Entrada Triage').first().json.body;
let poliza_data = null;
try {
  poliza_data = $('Consultar DB Póliza').first()?.json || null;
} catch (e) {
  poliza_data = null;
}

const fc = parseFloat(webhook_data.fc || 0);
const fr = parseFloat(webhook_data.fr || 0);
const pas = parseFloat(webhook_data.pas || 0);
const pad = parseFloat(webhook_data.pad || 0);
const triage_input = webhook_data.triage || 'Verde';

let triage_nivel = triage_input;
let triage_desc = 'Prioridad IV — Verde';

if (fc < 50 || fc > 150 || pas < 90 || pas > 220 || pad > 110 || fr > 35 || fr < 10) {
  triage_nivel = 'Rojo';
  triage_desc = 'Prioridad I — Rojo (Atención Inmediata)';
} else if (fr >= 24) {
  triage_nivel = 'Naranja';
  triage_desc = 'Prioridad II — Naranja (Muy Urgente)';
} else if (pas < 100 || fc > 100 || fr >= 20) {
  triage_nivel = 'Amarillo';
  triage_desc = 'Prioridad III — Amarillo (Urgente)';
}

const emergencia_calificada = ['Rojo', 'Naranja', 'Amarillo'].includes(triage_nivel);

const meses_vigencia = poliza_data ? (poliza_data.meses_vigencia || 0) : 0;
const sbu = poliza_data ? parseFloat(poliza_data.sbu_vigente || 460) : 460;
const sublimite_preexistencias = 20 * sbu;

const preexistencias_list = (poliza_data?.preexistencias && Array.isArray(poliza_data.preexistencias))
  ? poliza_data.preexistencias.join(', ')
  : 'Ninguna';

const ai_context = `Analiza el siguiente cuadro clínico de ingreso bajo las leyes y reglamentos de la República del Ecuador.

=== DATOS DE INGRESO A EMERGENCIAS ===
Paciente: ${webhook_data.paciente || poliza_data?.nombre_completo || 'Paciente Desconocido'}
Cédula: ${webhook_data.cedula}
Síntomas: ${webhook_data.sintomas}
Signos Vitales: FC ${fc} lpm, FR ${fr} rpm, PA ${pas}/${pad} mmHg.
Nivel de Triaje Manchester: ${triage_nivel} (${triage_desc})
Emergencia Calificada: ${emergencia_calificada ? 'SÍ' : 'NO'}

=== DATOS DE LA PÓLIZA ===
Estado de Póliza: ${poliza_data && poliza_data.estado_poliza ? poliza_data.estado_poliza : 'NO ENCONTRADA'}
Tipo de Póliza: ${poliza_data && poliza_data.tipo_poliza ? poliza_data.tipo_poliza : 'N/A'}
Vigencia: ${meses_vigencia} meses (Desde ${poliza_data && poliza_data.fecha_inicio ? poliza_data.fecha_inicio : 'N/A'})
Preexistencias Declaradas: ${preexistencias_list}
Notas: ${poliza_data && poliza_data.notes ? poliza_data.notes : ''}

=== MARCO REGULATORIO DE ECUADOR A APLICAR ===
1. Acuerdo Ministerial 000005169 (Triage Manchester MSP).
2. Art. 8, 12 y 13 de la Ley de Derechos y Amparo del Paciente.
3. Art. 34 de la Ley de Medicina Prepagada.
4. Condiciones de Aseguradora del Sur.
5. Lineamientos Obligatorios del MSP (Consumo de Sustancias).

=== INSTRUCCIONES DE RESPUESTA ===
Devuelve SOLO un JSON sin markdown ni texto adicional:
{
  "triaje_validado": "${triage_nivel}",
  "emergencia_calificada": ${emergencia_calificada},
  "poliza_activa": ${poliza_data && poliza_data.estado_poliza === 'ACTIVA' ? 'true' : 'false'},
  "cobertura_estado": "AUTORIZADO_INMEDIATO",
  "sublimite_aplicado_usd": ${emergencia_calificada ? sublimite_preexistencias : 0.00},
  "analisis_clinico_legal": "texto",
  "alerta_bloqueo_administrativo": "texto o null"
}`;

return [{ json: { webhook_data, poliza_data, triage_nivel, emergencia_calificada, ai_context } }];

const text = $json.text;
if (typeof text === 'string' && text.trim().length > 20 && !$json.error) {
  return [{ json: $json }];
}
return [];

const text = $json.text;
if (typeof text === 'string' && text.trim().length > 20 && !$json.error) {
  return [{ json: $json }];
}
return [];

// Buscar el primer resultado válido entre los 3 Gemini
function isValid(text) {
  return typeof text === 'string' && text.trim().length > 20 && !text.includes('"error"');
}

let raw_content = null;
let fuente_usada = 'bypass';

try {
  const g1 = $('1. Instancia Gemini (Principal)').first()?.json;
  if (g1 && isValid(g1.text)) { raw_content = g1.text; fuente_usada = 'Gemini-1-Flash'; }
} catch(e) {}

if (!raw_content) {
  try {
    const g2 = $('2. Instancia Gemini (Respaldo Pro)').first()?.json;
    if (g2 && isValid(g2.text)) { raw_content = g2.text; fuente_usada = 'Gemini-2-Pro'; }
  } catch(e) {}
}

if (!raw_content) {
  try {
    const g3 = $('3. Instancia Gemini (Respaldo Flash 2)').first()?.json;
    if (g3 && isValid(g3.text)) { raw_content = g3.text; fuente_usada = 'Gemini-3-Flash'; }
  } catch(e) {}
}

// Parsear JSON de la IA
let dictamen = null;
if (raw_content) {
  const cleaned = raw_content.replace(/```json\n?/gi, '').replace(/```\n?/g, '').trim();
  try {
    dictamen = JSON.parse(cleaned);
  } catch(e) {
    const match = cleaned.match(/{[\s\S]*}/);
    if (match) { try { dictamen = JSON.parse(match[0]); } catch(e2) {} }
  }
}

// Bypass catastrófico
if (!dictamen || typeof dictamen !== 'object') {
  let prep = { triage_nivel: 'Rojo' };
  try { prep = $('Preparar Variables').item.json; } catch(e) {}
  dictamen = {
    triaje_validado: prep.triage_nivel || 'Rojo',
    emergencia_calificada: true,
    poliza_activa: true,
    cobertura_estado: 'AUTORIZADO_INMEDIATO',
    sublimite_aplicado_usd: 9200.00,
    analisis_clinico_legal: 'Bypass activado por Failover general. Resguardo legal Art. 8 y 13.',
    alerta_bloqueo_administrativo: 'Alerta Administrativa Activa por colapso de red.'
  };
  fuente_usada = 'bypass-catastrofico';
}

// Normalizar
dictamen.triaje_validado = dictamen.triaje_validado || 'Rojo';
dictamen.emergencia_calificada = dictamen.emergencia_calificada !== false;
dictamen.poliza_activa = dictamen.poliza_activa !== false;
dictamen.cobertura_estado = dictamen.cobertura_estado || 'AUTORIZADO_INMEDIATO';
dictamen.sublimite_aplicado_usd = parseFloat(dictamen.sublimite_aplicado_usd || 0);
if (isNaN(dictamen.sublimite_aplicado_usd)) dictamen.sublimite_aplicado_usd = 0.00;

const raw_analisis = dictamen.analisis_clinico_legal || 'Sin análisis disponible.';
dictamen.analisis_clinico_legal = raw_analisis;
dictamen.analisis_clinico_legal_sql = raw_analisis.replace(/'/g, "''").replace(/[\r\n]+/g, ' ');
dictamen.alerta_bloqueo_administrativo = dictamen.alerta_bloqueo_administrativo || null;
dictamen.cobertura_otorgada_sql = dictamen.cobertura_estado === 'AUTORIZADO_INMEDIATO' ? 'true' : 'false';
dictamen.fuente_ia = fuente_usada;

return [{ json: dictamen }];

